import React, { useState, useEffect } from 'react';
import './App.css';
import HomePage from './component/HomePage';
import AddRoomPage from './component/AddRoomPage';
import Header from './component/Header';
import AddDecoPage from './component/AddDecoPage';
import EditRoom from './component/EditRoom';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MyRooms from './component/MyRooms';


function App() {
  const [rooms, setRooms] = useState([])

  let addRoom = (room) => {
    let r = rooms
    r.push(room)
    setRooms(r)
  }

  let addNewDeco = (name, newDeco) => {
    let r = rooms.map((i) => {
      if (i.name == name) {
        let l = i.items
        l.push(newDeco)
        return ({ name: i.name, roomType: i.roomType, roomColor: i.color, items: l })
      }
      else{
        return({ name: i.name, roomType: i.roomType, roomColor: i.color, items: i.items })}
    })
    setRooms(r)
  }
  let turnOnOrOff = (name, index, status) => {
    let r = rooms.map((i) => {
      if (i.name == name) {
        let l = i.items
        l[index]=status
        return({ name: i.name, roomType: i.roomType, roomColor: i.color, items: l })
      }
      else{
        return({ name: i.name, roomType: i.roomType, roomColor: i.color, items: i.items })}
    })
    setRooms(r)
  }

  return (
    <div className="App">
      <Header />
      <Router>
        <Routes>
          <Route path={'/'} element={<HomePage />} />
          <Route path={'/addroom'} element={<AddRoomPage addRoom={addRoom} />} />
          <Route path={'/myrooms'} element={<MyRooms rooms={rooms} />} />
          {rooms.map((item) => {
            return ( <Route path={item.name} element={<EditRoom room={item} />} />)})};
          {rooms.map((item) => {
            return (<Route path={item.name + "/additems"} element={<AddDecoPage name={item.name} addNewDeco={addNewDeco} />} />)})};
        </Routes>
      </Router>
    </div>)
}
export default App;
